const unitId = parseInt(msg.req.query.unitId) || 2;
const register = parseInt(msg.req.query.register) || 0;
const quantity = parseInt(msg.req.query.quantity) || 1;

msg.payload = {
    fc: 3,
    unitid: unitId,
    address: register,
    quantity: quantity
};
msg._unitId = unitId;
msg._register = register;
msg._quantity = quantity;

node.status({ fill: 'blue', shape: 'dot', text: `FC03 uid:${unitId} reg:${register} qty:${quantity}` });
return msg;

const unitId = msg._unitId || 2;
const register = msg._register || 0;
const raw = msg.payload;

// 레지스터 값을 릴레이 상태로 변환
// 보통 첫 번째 레지스터가 비트맵으로 8채널 상태를 담음
const regValue = raw[0] || 0;
const coils = {};
for (let i = 0; i < 8; i++) {
    coils[i] = !!(regValue & (1 << i));
}

msg.payload = {
    success: true,
    data: {
        unitId: unitId,
        register: register,
        raw: Array.isArray(raw) ? raw : [raw],
        regValue: regValue,
        coils: coils,
        timestamp: new Date().toISOString()
    }
};

node.status({ fill: 'green', shape: 'dot', text: `OK val:${regValue} @ ${new Date().toLocaleTimeString()}` });
return msg;

const body = msg.payload;
const unitId = parseInt(body.unitId) || 2;
const register = parseInt(body.register) || 0;
const value = parseInt(body.value) || 0;

msg.payload = {
    fc: 6,
    unitid: unitId,
    address: register,
    quantity: 1,
    value: value
};
msg._unitId = unitId;
msg._register = register;
msg._value = value;

node.status({ fill: 'yellow', shape: 'dot', text: `FC06 uid:${unitId} reg:${register} val:${value}` });
return msg;

const unitId = msg._unitId || 2;
const register = msg._register || 0;
const value = msg._value || 0;

msg.payload = {
    success: true,
    data: {
        unitId: unitId,
        register: register,
        value: value,
        timestamp: new Date().toISOString()
    }
};

node.status({ fill: 'green', shape: 'dot', text: `OK reg:${register} val:${value}` });
return msg;
